```typescript
import { fetch, post, get } from './http-client';
import { API_CONFIG, endpoints } from '../config/api-config';

const BASE_URL = API_CONFIG.baseUrl;

export async function fetchUserData(userId: string) {
  const url = `${BASE_URL}${endpoints.users}/${userId}`;
  return fetch(url, { method: 'GET' });
}

export async function createUser(data: UserPayload) {
  const url = `${BASE_URL}${endpoints.users}`;
  return post(url, data);
}
```

## Key Points

- **HTTP Client**: It uses functions from `./http-client` (`fetch`, `post`, `get`) — likely a wrapper around axios (I saw an axios import earlier).
- **Configuration**: API base URL and endpoints come from `../config/api-config`.
- **Two main functions**:
  - `fetchUserData(userId)` — GET request to fetch user data
  - `createUser(data)` — POST request to create a new user

